162	pub fn run(cmd: &str, args: &[&str], cwd: &Path) -> Result<String, Box<dyn std::error::Error>> {
163	    let args_str = args.join(" ");
164	    debug!("$ {cmd} {args_str}");
165	    trace!("cwd: {}", cwd.display());
166	    let output = std::process::Command::new(cmd)
167	        .args(args)
168	        .current_dir(cwd)
169	        .output()
170	        .map_err(|e| format!("failed to run {cmd}: {e}"))?;
171	    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
172	    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
173	    if !stdout.is_empty() {
174	        debug!("  {stdout}");
175	    }
176	    if !stderr.is_empty() {
177	        debug!("  {stderr}");
178	    }
179	    if !output.status.success() {
180	        return Err(format!("{cmd} {args_str} failed: {stderr}").into());
181	    }
182	    Ok(stdout)
183	}
