399	/// Expand comma-separated repo paths, default to `["."]`, and run a closure for each.
400	///
401	/// Header style controls output between repos.
402	/// Continues past errors, printing them to stderr, and returns an error if any failed.
403	pub fn for_each_repo<F>(
404	    raw_repos: &[PathBuf],
405	    header: &Header,
406	    mut body: F,
407	) -> Result<(), Box<dyn std::error::Error>>
408	where
409	    F: FnMut(&Workspace, &Arc<ReadonlyRepo>) -> Result<(), Box<dyn std::error::Error>>,
410	{
411	    let repos: Vec<PathBuf> = if raw_repos.is_empty() {
412	        vec![PathBuf::from(".")]
413	    } else {
414	        raw_repos
415	            .iter()
416	            .flat_map(|p| {
417	                p.to_string_lossy()
418	                    .split(',')
419	                    .map(|s| PathBuf::from(s.trim()))
420	                    .collect::<Vec<_>>()
421	            })
422	            .collect()
423	    };
424	    let multi = repos.len() > 1;
425	    let mut first = true;
426	    let mut errors: Vec<String> = Vec::new();
427	
428	    for repo_path in &repos {
429	        if multi {
430	            match header {
431	                Header::Label(deco) => {
432	                    if !first {
433	                        info!("");
434	                    }
435	                    info!(
436	                        "{}",
437	                        bold(&format!("{deco} {} {deco}", repo_path.display()))
438	                    );
439	                }
440	                Header::None => {}
441	            }
442	        }
443	        first = false;
444	
445	        match load_repo(repo_path) {
446	            Ok((workspace, repo)) => {
447	                if let Err(e) = body(&workspace, &repo) {
448	                    error!("({}): {e}", repo_path.display());
449	                    errors.push(format!("{}: {e}", repo_path.display()));
450	                }
451	            }
452	            Err(e) => {
453	                error!("({}): {e}", repo_path.display());
454	                errors.push(format!("{}: {e}", repo_path.display()));
455	            }
456	        }
457	    }
458	
459	    if errors.is_empty() {
460	        Ok(())
461	    } else {
462	        Err(format!("{} repo(s) had errors", errors.len()).into())
463	    }
464	}
