466	pub fn load_repo(
467	    path: &Path,
468	) -> Result<(Workspace, Arc<ReadonlyRepo>), Box<dyn std::error::Error>> {
469	    let config = StackedConfig::with_defaults();
470	    let settings = UserSettings::from_config(config)?;
471	    let store_factories = StoreFactories::default();
472	    let working_copy_factories = default_working_copy_factories();
473	
474	    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
475	    let repo = workspace.repo_loader().load_at_head().block_on()?;
476	
477	    Ok((workspace, repo))
