133	pub fn init(args: &InitArgs) -> Result<(), Box<dyn std::error::Error>> {
134	    debug!("init: enter");
135	    let parent_dir = match &args.dir {
136	        Some(d) => d.clone(),
137	        None => std::env::current_dir()?,
138	    };
139	    let project_dir = parent_dir.join(&args.name);
140	    let session_dir = project_dir.join(".claude");
141	
142	    // Preflight checks
143	    info!("Preflight checks...");
144	
145	    // Check tools
146	    run("gh", &["auth", "status"], Path::new("."))
147	        .map_err(|_| "gh is not installed or not authenticated (run: gh auth login)")?;
148	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
149	
150	    let owner = match &args.owner {
151	        Some(o) => o.clone(),
152	        None => gh_whoami()?,
153	    };
154	
155	    if project_dir.exists() {
156	        return Err(format!("'{}' already exists", project_dir.display()).into());
157	    }
158	
159	    let code_repo = format!("{owner}/{}", args.name);
160	    let session_repo = format!("{owner}/{}.claude", args.name);
161	
162	    if gh_repo_exists(&owner, &args.name)? {
163	        return Err(format!("GitHub repo '{code_repo}' already exists").into());
164	    }
165	    if gh_repo_exists(&owner, &format!("{}.claude", args.name))? {
166	        return Err(format!("GitHub repo '{session_repo}' already exists").into());
167	    }
168	
169	    let visibility = if args.private {
170	        "--private"
171	    } else {
172	        "--public"
173	    };
174	
175	    if args.dry_run {
176	        info!("Dry run — would execute:");
177	        info!("  1. Create directories: {}", project_dir.display());
178	        info!("  2. git init + jj git init --colocate on both repos");
179	        info!("  3. Write .vc-config.toml and .gitignore to both");
180	        info!("  4. jj commit both with placeholder ochids");
181	        info!("  5. Get both chids, jj describe both with correct ochids");
182	        info!("  6. Remove jj from both (git clean -xdf)");
183	        info!("  7. gh repo create {session_repo} {visibility}, push");
184	        info!("  8. gh repo create {code_repo} {visibility}, push");
185	        info!("  9. jj git init --colocate on both repos");
186	        info!("  10. Create Claude Code symlink");
187	        return Ok(());
188	    }
189	
190	    // Step 1: Create directories
191	    info!("Step 1: Creating project directories...");
192	    mkdir_p(&project_dir)?;
193	    mkdir_p(&session_dir)?;
194	
195	    // Step 2: git init + jj init on both repos
196	    info!("Step 2: Initializing repos...");
197	    run("git", &["init"], &project_dir)?;
198	    run("jj", &["git", "init", "--colocate"], &project_dir)?;
199	    run("git", &["init"], &session_dir)?;
200	    run("jj", &["git", "init", "--colocate"], &session_dir)?;
201	
202	    // Step 3: Write config files
203	    info!("Step 3: Writing config files...");
204	    write_file(&project_dir.join(".vc-config.toml"), VC_CONFIG_CODE)?;
205	    write_file(&project_dir.join(".gitignore"), GITIGNORE_CODE)?;
206	    write_file(&session_dir.join(".vc-config.toml"), VC_CONFIG_SESSION)?;
207	    write_file(&session_dir.join(".gitignore"), GITIGNORE_SESSION)?;
208	
209	    // Step 4: jj commit both with placeholder ochids
210	    info!("Step 4: Committing both repos with placeholder ochids...");
211	    run(
212	        "jj",
213	        &["commit", "-m", "Initial commit\n\nochid: /none"],
214	        &project_dir,
215	    )?;
216	    run(
217	        "jj",
218	        &["commit", "-m", "Initial commit\n\nochid: /none"],
219	        &session_dir,
220	    )?;
221	
222	    // Step 5: Get both chids, then describe both with correct ochids
223	    info!("Step 5: Setting ochid cross-references...");
224	    let code_chid = jj_chid("@-", &project_dir)?;
225	    let session_chid = jj_chid("@-", &session_dir)?;
226	
227	    let code_desc = format!("Initial commit\n\nochid: /.claude/{session_chid}");
228	    let session_desc = format!("Initial commit\n\nochid: /{code_chid}");
229	    run("jj", &["describe", "@-", "-m", &code_desc], &project_dir)?;
230	    run("jj", &["describe", "@-", "-m", &session_desc], &session_dir)?;
231	
232	    {
233	        let hash = run("git", &["rev-parse", "HEAD"], &project_dir)?;
234	        debug!("code repo: chid={code_chid} hash={hash}");
235	        let hash = run("git", &["rev-parse", "HEAD"], &session_dir)?;
236	        debug!(".claude:   chid={session_chid} hash={hash}");
237	    }
238	
239	    // Step 6: Set bookmarks (creates git branches), then remove jj
240	    // Bookmarks must be set before removing .jj/ so git has a 'main' branch to push
241	    info!("Step 6: Setting bookmarks and removing jj...");
