use clap::Args;
use log::{debug, info};

use crate::common::{mkdir_p, run, write_file};

/// Create a throwaway jj repo + local bare git remote for testing.
///
/// Designed for exercising `finalize` and other subcommands without touching
/// live session or project repos. Produces a tracked `main` bookmark on a
/// described commit so `--push` flows work end-to-end.
#[derive(Args, Debug)]
pub struct TestFixtureArgs {
    /// Fixture root directory [default: $TMPDIR/vc-x1-test-<timestamp>]
    #[arg(long, value_name = "PATH")]
    pub path: Option<PathBuf>,
}

pub fn test_fixture(args: &TestFixtureArgs) -> Result<(), Box<dyn std::error::Error>> {
    debug!("test_fixture: enter");

    let base = match &args.path {
        Some(p) => p.clone(),
        None => {
            let ts = SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .map_err(|e| format!("time error: {e}"))?
                .as_nanos();
            std::env::temp_dir().join(format!("vc-x1-test-{ts}"))
        }
    };

    if base.exists() {
        return Err(format!("'{}' already exists", base.display()).into());
    }

    info!("Creating test fixture at {}", base.display());

    let remote_dir = base.join("remote.git");
    let work_dir = base.join("work");
    mkdir_p(&base)?;
    mkdir_p(&remote_dir)?;
    mkdir_p(&work_dir)?;

