    let remote_url = remote_dir.canonicalize()?.to_string_lossy().into_owned();
    run("git", &["remote", "add", "origin", &remote_url], &work_dir)?;
    run("jj", &["git", "push", "--bookmark", "main"], &work_dir)?;
    run("jj", &["bookmark", "track", "main@origin"], &work_dir)?;

